# -*- coding: utf-8 -*-
"""Lightweight i18n for Launchpad Deck. t(key) -> string in the current language.
Fallback chain: current -> English -> Russian -> key itself."""

LANG_NAMES = {
    "ru": "Русский", "en": "English", "uk": "Українська",
    "de": "Deutsch", "es": "Español", "fr": "Français",
}
LANG_ORDER = ["ru", "en", "uk", "de", "es", "fr"]

_cur = ["ru"]


def set_current(code):
    if code in LANG_NAMES:
        _cur[0] = code


def current():
    return _cur[0]


def t(key):
    d = LANGS.get(_cur[0], {})
    if key in d:
        return d[key]
    en = LANGS.get("en", {})
    if key in en:
        return en[key]
    return LANGS["ru"].get(key, key)


